class Solution {
    private int[] w;
    private double[] cumulativeProbabilities;

    public Solution(int[] w) {
        this.w = w;
        cumulativeProbabilities = new double[w.length];
        cumulativeProbabilities[0] = (double) w[0] / sum(w);
        for (int i = 1; i < w.length; i++) {
            cumulativeProbabilities[i] = cumulativeProbabilities[i - 1] + (double) w[i] / sum(w);
        }
    }

    public int pickIndex() {
        double randomValue = Math.random() * sum(w);
        int index = 0;
        while (index < cumulativeProbabilities.length - 1 && randomValue >= cumulativeProbabilities[index]) {
            index++;
        }
        return index;
    }

    private int sum(int[] arr) {
        int sum = 0;
        for (int num : arr) {
            sum += num;
        }
        return sum;
    }
}
